async function run(params, api) {
  var repo = params.repo;
  var limit = Math.min(params.limit || 10, 30);
  var qs = '?per_page=' + limit;
  if (params.branch) qs += '&sha=' + encodeURIComponent(params.branch);
  if (params.path) qs += '&path=' + encodeURIComponent(params.path);
  var url = 'https://api.github.com/repos/' + repo + '/commits' + qs;
  api.log('Fetching commits: ' + repo);
  var raw = await api.httpGet(url);
  var data = JSON.parse(raw);
  var commits = data.map(function(c) {
    return {
      sha: c.sha.slice(0, 7),
      message: c.commit.message.split('\n')[0].slice(0, 120),
      author: c.commit.author.name,
      date: c.commit.author.date,
      url: c.html_url
    };
  });
  return JSON.stringify({ repo: repo, count: commits.length, commits: commits }, null, 2);
}
